![medium](https://www.gstatic.com/codereviewagent/medium-priority.svg)

The `waitAck` function is typed to return `Promise<void>` and resolves with no value. However, the call site in `sendBlob` (line 131) assigns the result of `reqAck` to `beginResp` and logs it (line 148), expecting to see the acknowledgment payload. This currently results in `beginResp` always being `undefined`.

To fix this, `waitAck` should resolve with the message payload (`resolve(m.payload)`) and its return type should be updated to `Promise<any>`. Consequently, `reqAck` should be updated to return this payload. This will ensure the log at line 148 works as intended and correctly displays the response from the background script.

```typescript
  private waitAck(match: (m: any) => boolean, backpressureRetry?: number) {
    return new Promise<any>((resolve, reject) => {
      const t = setTimeout(() => {
        off()
        reject(new Error('ACK timeout'))
      }, ACK_TIMEOUT_MS)
      const on = (m: any) => {
        // Check for EXPORT_FAILED first
        if (m?.type === 'EXPORT_FAILED') {
          clearTimeout(t)
          off()
          reject(
            new Error(`Export failed: ${m.payload?.reason || 'Unknown error'}`),
          )
          return
        }
        // Handle backpressure with exponential backoff
        if (m?.type === 'EXPORT_BACKPRESSURE') {
          clearTimeout(t)
          off()
          const retryCount = Math.min(
            backpressureRetry ?? 0,
            MAX_BACKPRESSURE_RETRIES,
          )
          const delay = Math.min(
            BACKPRESSURE_BASE_DELAY_MS * Math.pow(2, retryCount),
            BACKPRESSURE_MAX_DELAY_MS,
          )
          logger.debug(
            `Backpressure received, retrying in ${delay}ms (attempt ${retryCount + 1})`,
          )
          reject({ isBackpressure: true, retryCount, delay })
          return
        }
        if (match(m)) {
          clearTimeout(t)
          off()
          resolve(m.payload)
        }
      }
      const off = () => this.port.onMessage.removeListener(on)
      this.port.onMessage.addListener(on)
    })
  }

  private async reqAck(msg: any, matcher: (m: any) => boolean) {
    let backpressureRetry = 0
    for (let attempt = 0; attempt <= MAX_RETRY; attempt++) {
      this.port.postMessage(msg)
      try {
        const payload = await this.waitAck(matcher, backpressureRetry)
        return payload
      } catch (e: any) {
        // Handle backpressure with exponential backoff
        if (e?.isBackpressure) {
          await new Promise(resolve => setTimeout(resolve, e.delay))
          backpressureRetry = e.retryCount + 1
          // Don't count backpressure as a retry attempt
          attempt--
          continue
        }
        if (attempt === MAX_RETRY) throw e
      }
    }
  }
```
